import asyncio, anthropic
from circuitbreaker import circuit

client = anthropic.AsyncAnthropic()

@circuit(failure_threshold=5, recovery_timeout=60)
async def call_claude(system: str, user_message: str) -> str:
    response = await client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        system=system,
        messages=[{"role": "user", "content": user_message}]
    )
    return response.content[0].text

async def handle_request(system: str, message: str) -> dict:
    try:
        result = await call_claude(system, message)
        return {"status": "ok", "response": result}
    except Exception:
        # Circuit open or API error — return fallback
        return {
            "status": "fallback",
            "response": "The assistant is temporarily unavailable. Please try again in a moment or contact support."
        }
